import { Component, h, Element, State } from '@stencil/core';

@Component({
  tag: 'wdpr-carousel',
  styleUrl: 'wdpr-carousel.css',
  shadow: true,
})
export class WdprCarousel {
  private _scrollContainer?: HTMLDivElement;
  private _itemWidth: number = 0;
  private _resizeObserver?: ResizeObserver;

  @Element() el: HTMLWdprCarouselElement;

  @State() _showNavigationButtons: boolean = false;
  @State() _atStart: boolean = true;
  @State() _atEnd: boolean = false;

  componentDidLoad() {
    this._initializeCarousel();
  }

  disconnectedCallback() {
    this._cleanupCarousel();
  }

  private _initializeCarousel = () => {
    if (!this._scrollContainer) return;

    this._scrollContainer.addEventListener('scroll', this._updateScrollPosition);
    this._resizeObserver = new ResizeObserver(this._refreshCarouselState);
    this._resizeObserver.observe(this._scrollContainer);
    this._refreshCarouselState();
  };

  private _cleanupCarousel = () => {
    if (this._scrollContainer) {
      this._scrollContainer.removeEventListener('scroll', this._updateScrollPosition);
    }
    this._resizeObserver?.disconnect();
  };

  private _getSlotElements = () => {
    return this._scrollContainer?.querySelector('slot')?.assignedElements() || [];
  };

  private _calculateItemWidth = () => {
    const elements = this._getSlotElements();
    const firstItem = elements[0];
    this._itemWidth = firstItem instanceof HTMLElement ? firstItem.offsetWidth : 0;
  };

  private _updateTotalItemsAndClass = () => {
    const elements = this._getSlotElements();
    const totalItems = elements.length;

    // Update CSS custom property
    this.el.style.setProperty('--total-items', totalItems.toString());

    // Update fewer-items class based on visible items
    const computedStyle = getComputedStyle(this.el);
    const maxVisibleItems = parseFloat(computedStyle.getPropertyValue('--max-visible-items') || '1');

    this.el.classList.toggle('fewer-items', totalItems < maxVisibleItems);
  };

  private _checkOverflow = () => {
    if (!this._scrollContainer) return;
    this._showNavigationButtons = this._scrollContainer.scrollWidth > this._scrollContainer.clientWidth;
  };

  private _updateScrollPosition = () => {
    if (!this._scrollContainer) return;

    const { scrollLeft, scrollWidth, clientWidth } = this._scrollContainer;
    const maxScrollLeft = scrollWidth - clientWidth;
    const threshold = 2;

    this._atStart = scrollLeft <= threshold;
    this._atEnd = scrollLeft >= maxScrollLeft - threshold;
  };

  private _scrollByItemWidth = (direction: 'prev' | 'next') => {
    if (!this._scrollContainer || !this._itemWidth) return;

    const scrollDistance = direction === 'prev' ? -this._itemWidth : this._itemWidth;
    this._scrollContainer.scrollBy({
      left: scrollDistance,
      behavior: 'smooth',
    });
  };

  private _handlePrev = () => {
    this._scrollByItemWidth('prev');
  };
  private _handleNext = () => {
    this._scrollByItemWidth('next');
  };

  private _refreshCarouselState = () => {
    this._updateTotalItemsAndClass();
    this._calculateItemWidth();
    this._checkOverflow();
    this._updateScrollPosition();
  };

  private _handleSlotChange = () => {
    this._refreshCarouselState();
  };

  private get _showPrevButton(): boolean {
    return this._showNavigationButtons && !this._atStart;
  }

  private get _showNextButton(): boolean {
    return this._showNavigationButtons && !this._atEnd;
  }

  render() {
    return (
      <section class="relative">
        {this._showPrevButton && (
          <wdpr-icon-button
            class="absolute left-0 top-1/2 translate-x-0 -translate-y-1/2 z-10 hidden lg:block"
            iconName="previous"
            variant="bgPrimary"
            a11yLabel="Previous Card"
            onClicked={this._handlePrev}
          />
        )}
        <div class="overflow-x-visible lg:overflow-x-scroll no-scrollbar py-300 lg:pointer-events-none" ref={el => (this._scrollContainer = el as HTMLDivElement)}>
          <div class="scroll-items-container grid grid-flow-col">
            <slot onSlotchange={this._handleSlotChange} />
          </div>
        </div>
        {this._showNextButton && (
          <wdpr-icon-button
            class="absolute right-0 top-1/2 translate-x-0 -translate-y-1/2 z-10 hidden lg:block"
            iconName="next"
            variant="bgPrimary"
            a11yLabel="Next Card"
            onClicked={this._handleNext}
          />
        )}
      </section>
    );
  }
}
